export const SportsIcon = ({ size = 20, color = "#006493", sportId = 99 }) => {
  switch (sportId) {
    case 1:
      return <FutsalIcon size={size} color={color} />;
    case 2:
      return <MiniSoccerIcon size={size} color={color} />;
    case 3:
      return <FootballIcon size={size} color={color} />;
    case 4:
      return <BasketballIcon size={size} color={color} />;
    case 5:
      return <VolleyballIcon size={size} color={color} />;
    case 6:
      return <TennisIcon size={size} color={color} />;
    case 7:
      return <TableTennisIcon size={size} color={color} />;
    case 10:
      return <BadmintonIcon size={size} color={color} />;
    case 11:
      return <BaseballIcon size={size} color={color} />;
    case 12:
      return <SquashIcon size={size} color={color} />;
    case 13:
      return <PadelIcon size={size} color={color} />;
    default:
      return <OthersIcon size={size} color={color} />;
  }
};
